<!DOCTYPE html>
<html lang="it">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>AI Codex – Negozio di Programmazione AI</title>
    <style>
        /* Reset base */
        * {
        margin: 0;
        padding: 0;
        box-sizing: border-box;
        font-family: 'system-ui, 'Segoe UI, Roboto, 'Helvetica, sans-serif';
        scroll-behavior: smooth;
        transition: all 0.0s ease;
        /* cyberpunk */
        background: #0d0c15;
        color: #e0f0ff;
    }

        body {
        background: #0d0c15;
        min-height: 100vh;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        padding: 2rem 1rem;
        }

        .page {
        max-width: 1200px;
        width: 100%;
        background: rgba(10, 10, 20, 0.8);
        border: 1px solid #00ffff33;
        border-radius: 24px 24px 24px 24px;
        padding: 2rem 2rem 3rem;
        box-shadow: 0 0 40px #0ff4, 0 0 20px #0ff2;
        backdrop-filter: blur(4px);
        transition: 0.3s;
        }

        .header {
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 0.5rem;
        margin-bottom: 2rem;
        border-bottom: 1px solid #0ff8;
        padding-bottom: 1.5rem;
        }

        .header h1 {
        font-size: 2.8rem;
        font-weight: 900;
        letter-spacing: 4px;
        text-shadow: 0 0 20px #0ff, 0 0 30px #0ff4, 0 0 10px #0ff;
        background: linear-gradient 90deg, #0ff, #f0f, #ff0;
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        margin: 0;
        text-align: center;
        line-height: 1.2;
        filter: drop-shadow: 0 0 10px #0ff;
        }

        .header p {
        font-size: 1.2rem;
        color: #b0f0ff;
        text-shadow: 0 0 5px #0ff8;
        border: 1px solid #0ff3;
        padding: 0.5rem 1.5rem;
        border-radius: 40px;
        background: #0ff1;
        letter-spacing: 2px;
        margin: 0.5rem 0;
        }

        .hero {
        display: flex;
        flex-wrap: wrap;
        gap: 2rem;
        justify-content: center;
        align-items: center;
        margin: 2rem 0;
        padding: 1rem 0;
        border-bottom: 1px dashed #0ff5;
        border-top: 1px dashed #0ff5;
        }

        .hero-text {
        flex: 1;
        min-width: 280px;
        text-align: center;
        font-size: 1.2rem;
        line-height: 1.6;
        color: #dbfff;
        text-shadow: 0 0 2px #0ff;
        padding: 1rem;
        border: 1px solid #0ff4;
        border-radius: 12px;
        background: #0a0a12;
        box-shadow: inset 0 0 20px #0ff2;
        }

        .hero-text strong {
        color: #f0f;
        font-weight: bold;
        background: #f0f2;
        padding: 0 4px;
        border-radius: 4px;
        }

        .hero .ctat {
        background: #0ff;
        color: #0a0a12;
        font-weight: bold;
        padding: 0.8rem 2rem;
        border-radius: 40px;
        text-decoration: none;
        letter-spacing: 2px;
        box-shadow: 0 0 20px #0ff, 0 0 10px #0ff7;
        transition: 0.3s;
        border: 1px solid #fff;
        font-size: 1.4rem;
        background: linear-gradient 90deg, #0ff, #f0f, #ff0;
        background-clip: padding-box;
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        border: 2px solid #0ff;
        display: inline-block;
        margin: 1rem;
        cursor: pointer;
        transition: 0.2s;
        filter: drop-shadow: 0 0 10px #0ff;
        }

